class Solution:
    def findSubtreeSizes(self, parent, s):
        n = len(parent)
        new_parent = list(parent)
        for x in range(1, n):
            y = parent[x]
            found = -1
            while y != -1:
                if s[y] == s[x]:
                    found = y
                    break
                y = parent[y]
            if found != -1:
                new_parent[x] = found
        new_children = [[] for _ in range(n)]
        for i in range(1, n):
            new_children[new_parent[i]].append(i)
        size = [1] * n

        def dfs(x):
            for y in new_children[x]:
                dfs(y)
                size[x] += size[y]

        dfs(0)
        return size

