class Solution:
    def findSubtreeSizes(self, parent: List[int], s: str) -> List[int]:
        n = len(parent)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parent[i]].append(i)
        new_parent = list(parent)
        letter_stack = [[] for _ in range(26)]
        c0 = ord(s[0]) - 97
        letter_stack[c0].append(0)
        stack = [[0, 0]]
        while stack:
            node, idx = stack[-1]
            if idx < len(children[node]):
                stack[-1][1] += 1
                child = children[node][idx]
                c = ord(s[child]) - 97
                if letter_stack[c]:
                    new_parent[child] = letter_stack[c][-1]
                letter_stack[c].append(child)
                stack.append([child, 0])
            else:
                c = ord(s[node]) - 97
                letter_stack[c].pop()
                stack.pop()
        new_children = [[] for _ in range(n)]
        for i in range(1, n):
            new_children[new_parent[i]].append(i)
        size = [1] * n
        order = []
        stack2 = [0]
        while stack2:
            node = stack2.pop()
            order.append(node)
            for ch in new_children[node]:
                stack2.append(ch)
        for node in reversed(order):
            if node != 0:
                size[new_parent[node]] += size[node]
        return size

