var findSubtreeSizes = function(parent, s) {
    const n = parent.length;
    const children = Array.from({ length: n }, () => []);
    for (let i = 1; i < n; i++) children[parent[i]].push(i);
    const newParent = parent.slice();
    const letterStack = Array.from({ length: 26 }, () => []);
    letterStack[s.charCodeAt(0) - 97].push(0);
    const stack = [[0, 0]];
    while (stack.length) {
        const top = stack[stack.length - 1];
        const node = top[0];
        if (top[1] < children[node].length) {
            const child = children[node][top[1]];
            top[1]++;
            const c = s.charCodeAt(child) - 97;
            if (letterStack[c].length) {
                newParent[child] = letterStack[c][letterStack[c].length - 1];
            }
            letterStack[c].push(child);
            stack.push([child, 0]);
        } else {
            const c = s.charCodeAt(node) - 97;
            letterStack[c].pop();
            stack.pop();
        }
    }
    const newChildren = Array.from({ length: n }, () => []);
    for (let i = 1; i < n; i++) newChildren[newParent[i]].push(i);
    const size = new Array(n).fill(1);
    const order = [];
    const stack2 = [0];
    while (stack2.length) {
        const node = stack2.pop();
        order.push(node);
        for (const ch of newChildren[node]) stack2.push(ch);
    }
    for (let i = order.length - 1; i >= 0; i--) {
        const node = order[i];
        if (node !== 0) size[newParent[node]] += size[node];
    }
    return size;
};
